const todos = $input.all().map(t => t.json);
const now = new Date();
const today = now.toISOString().split('T')[0];
const hour = now.getHours();
const isMorning = hour < 12;

const pending = todos.filter(t => t.status === 'pending');
const todayCompleted = todos.filter(t => t.status === 'completed' && t.completed_at && t.completed_at.startsWith(today));
const yesterdayStr = new Date(now - 86400000).toISOString().split('T')[0];
const yesterdayCompleted = todos.filter(t => t.status === 'completed' && t.completed_at && t.completed_at.startsWith(yesterdayStr));

let msg = '';

if (isMorning) {
  // Morning message
  msg = `\ud83c\udf05 *Good Morning, Vishal!*\n\n`;

  if (yesterdayCompleted.length > 0) {
    msg += `\u2705 ${yesterdayCompleted.length} tasks completed yesterday\n\n`;
  }

  if (pending.length > 0) {
    msg += `\ud83d\udccb *Today's Tasks (${pending.length}):*\n`;
    pending.sort((a, b) => {
      const p = { high: 0, medium: 1, low: 2 };
      return (p[a.priority] || 1) - (p[b.priority] || 1);
    });
    pending.forEach((t, i) => {
      const icon = t.priority === 'high' ? '\ud83d\udd34' : t.priority === 'medium' ? '\ud83d\udfe1' : '\ud83d\udfe2';
      msg += `${i + 1}. ${icon} ${t.task}\n`;
    });
    msg += `\nLet's make today count! \ud83d\udcaa`;
  } else {
    msg += `No pending tasks! Time to plan your day. \ud83c\udfaf`;
  }
} else {
  // Evening recap
  msg = `\ud83c\udf19 *Evening Recap*\n\n`;

  if (todayCompleted.length > 0) {
    msg += `\u2705 *Completed today (${todayCompleted.length}):*\n`;
    todayCompleted.forEach(t => {
      msg += `  \u2713 ${t.task}\n`;
    });
    msg += `\n`;
  }

  if (pending.length > 0) {
    msg += `\u23f3 *Still pending (${pending.length}):*\n`;
    pending.forEach(t => {
      msg += `  \u25cb ${t.task}\n`;
    });
    msg += `\n_These will carry forward to tomorrow._\n`;
  }

  const total = todayCompleted.length + pending.length;
  const completionRate = total > 0 ? Math.round(todayCompleted.length / total * 100) : 0;

  if (completionRate >= 80) msg += `\n\ud83c\udf1f Great day! ${completionRate}% completion rate!`;
  else if (completionRate >= 50) msg += `\n\ud83d\udc4d Decent progress! ${completionRate}% done.`;
  else if (total > 0) msg += `\n\ud83d\udcaa Tomorrow is a fresh start! ${completionRate}% today.`;
}

return [{ json: { message: msg } }];
